namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0
        ? Math.Round(Ratings.Average(), 1)
        : 0;

    public int RatingCount => Ratings.Count;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                Ratings = [5, 4, 5, 4, 5]
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale or pancetta\nEgg yolks\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk egg yolks with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale, then remove from heat.\n5. Stir in the egg mixture quickly, tossing to coat.\n6. Serve immediately with extra cheese and pepper.",
                Ratings = [5, 5, 4]
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nCrushed tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt and spices for at least 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pan.\n4. Add crushed tomatoes and simmer 15 minutes.\n5. Stir in cream, add chicken pieces.\n6. Simmer 10 minutes and serve over rice.",
                Ratings = [5, 4, 5, 5]
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nBrown sugar\nGarlic",
                Steps = "1. Soak rice noodles in warm water for 20 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Mix fish sauce, tamarind paste, and brown sugar for sauce.\n4. Stir-fry garlic, then add noodles and sauce.\n5. Toss in bean sprouts and green onions.\n6. Serve with crushed peanuts and lime wedges.",
                Ratings = [4, 4, 5]
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
                Steps = "1. Brown ground beef in a skillet over medium-high heat.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan or microwave.\n4. Assemble tacos with beef, lettuce, tomato, and cheese.\n5. Top with sour cream and salsa.",
                Ratings = [4, 5, 4, 4]
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs, add flour.\n5. Pour into greased ramekins.\n6. Bake 12-14 minutes until edges are firm but center is soft.\n7. Invert onto plates and serve immediately.",
                Ratings = [5, 5, 5, 4, 5]
            },
        ];
        _nextId = 7;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }
}

