@using RecipeCommunity.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _selectedRating ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => _hoverRating = star"
              @onmouseout="() => _hoverRating = 0"
              style="cursor:pointer; font-size:1.5rem; color: @(star <= (_hoverRating > 0 ? _hoverRating : _selectedRating) ? "#ffc107" : "#ccc");">
            ★
        </span>
    }
    <span class="text-muted small">
        @if (_submitted)
        {
            <text>Thanks for rating!</text>
        }
        else
        {
            <text>(@RatingCount ratings, avg @AverageRating)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _selectedRating;
    private int _hoverRating;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        if (_submitted) return;

        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }

        _submitted = true;
    }
}

@using RecipeCommunity.Models
@using RecipeCommunity.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="_model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Thai">Thai</option>
            <option value="Mexican">Mexican</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="_model.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="_model.Steps" />
    </div>

    <button type="submit" class="btn btn-success" disabled="@_submitted">
        @if (_submitted)
        {
            <text>✓ Submitted!</text>
        }
        else
        {
            <text>Submit Recipe</text>
        }
    </button>
</EditForm>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your recipe "<strong>@_submittedTitle</strong>" has been added!
        <a href="/recipes/@_submittedCategory">View category →</a>
    </div>
}

@code {
    private RecipeFormModel _model = new();
    private bool _submitted;
    private string _submittedTitle = "";
    private string _submittedCategory = "";

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };

        RecipeService.AddRecipe(recipe);
        _submittedTitle = recipe.Title;
        _submittedCategory = recipe.Category;
        _submitted = true;
        _model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = "";
    }
}

