@using RecipeCommunity.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _selectedRating ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => _hoverRating = star"
              @onmouseout="() => _hoverRating = 0"
              style="cursor:pointer; font-size:1.5rem; color: @(star <= (_hoverRating > 0 ? _hoverRating : _selectedRating) ? "#ffc107" : "#ccc");">
            ★
        </span>
    }
    <span class="text-muted small">
        @if (_submitted)
        {
            <text>Thanks for rating!</text>
        }
        else
        {
            <text>(@RatingCount ratings, avg @AverageRating)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _selectedRating;
    private int _hoverRating;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        if (_submitted) return;

        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }

        _submitted = true;
    }
}

