@page "/recipes/{Category}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@Category Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

<h1>@Category Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row g-4">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted mb-2">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = "";

    private IReadOnlyList<RecipeCommunity.Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(Category);
    }
}

